const intent = $json.intent || '';
const params = $json.intentParams || {};
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY || '';
const accessToken = $env.GOOGLE_ACCESS_TOKEN || '';

if (!GOOGLE_API_KEY && !accessToken) {
  return [{ json: { ...$json, responseText: '⚠️ Google API credentials not configured.', success: false } }];
}

let endpoint, body, method = 'GET';
if (intent === 'docs_create') {
  endpoint = 'https://docs.googleapis.com/v1/documents';
  method = 'POST';
  body = { title: params.title || 'Untitled Document' };
} else if (intent === 'docs_read') {
  const docId = params.document_id || params.id;
  if (!docId) return [{ json: { ...$json, responseText: '❗ Document ID required.', success: false } }];
  endpoint = `https://docs.googleapis.com/v1/documents/${docId}`;
} else if (intent === 'docs_edit') {
  const docId = params.document_id || params.id;
  if (!docId) return [{ json: { ...$json, responseText: '❗ Document ID required.', success: false } }];
  const { requests } = params;
  if (!requests || !Array.isArray(requests)) return [{ json: { ...$json, responseText: '❗ requests array required.', success: false } }];
  endpoint = `https://docs.googleapis.com/v1/documents/${docId}:batchUpdate`;
  method = 'POST';
  body = { requests };
} else {
  return [{ json: { ...$json, responseText: '❓ Unknown Docs intent: ' + intent, success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiBody: body, apiMethod: method } }];

if ($json.documentId) {
  const url = `https://docs.google.com/document/d/${$json.documentId}/edit`;
  return [{ json: { ...$input.item.json, responseText: `📄 Document created!

<b>${$json.title}</b>

🔗 ${url}`, success: true } }];
} else if ($json.title) {
  return [{ json: { ...$input.item.json, responseText: `📄 Document: ${$json.title}
ID: ${$json.documentId || 'N/A'}`, success: true } }];
}
return [{ json: { ...$input.item.json, responseText: `📄 Document operation completed.`, success: true } }];
